import{c as a,a7 as i,y as e,B as s}from"./chunks/framework.3cjvm90C.js";const B=JSON.parse('{"title":"Qatten 多智能体值分解","description":"介绍 Qatten 如何利用多头注意力机制实现联合值函数分解","frontmatter":{"title":"Qatten 多智能体值分解","description":"介绍 Qatten 如何利用多头注意力机制实现联合值函数分解"},"headers":[],"relativePath":"rlwiki/papers/qatten.md","filePath":"rlwiki/papers/qatten.md","lastUpdated":1782448598000}'),n={name:"rlwiki/papers/qatten.md"};function E(p,t,l,r,A,h){return i(),e("div",null,[...t[0]||(t[0]=[s('<h2 id="创新点及贡献" tabindex="-1">创新点及贡献 <a class="header-anchor" href="#创新点及贡献" aria-label="Permalink to “创新点及贡献”">​</a></h2><p>1、研究了最值点附近联合行为值函数的分解性质，然后从理论分析层面进行网络结构涉及从而逼近理论分析结果，其中主要采用了 multiple attention heads 机制来实现对理论分析结果的逼近。</p><h2 id="研究痛点" tabindex="-1">研究痛点 <a class="header-anchor" href="#研究痛点" aria-label="Permalink to “研究痛点”">​</a></h2><p>1、文章重点研究的还是值分解技术， VDN 的假设过于严格，且忽略了全局信息； QMIX 将 mix 过程视为一个黑盒； QTRAN 的优化问题约束需要通过惩罚项进行解决，从而偏离了真实的结果。</p><h2 id="算法流程" tabindex="-1">算法流程 <a class="header-anchor" href="#算法流程" aria-label="Permalink to “算法流程”">​</a></h2><p>算法框架如下</p><p><img src="https://liushunyu.github.io/img/in-post/2020-07-07-%E5%BC%BA%E5%8C%96%E5%AD%A6%E4%B9%A0%E8%AE%BA%E6%96%87%EF%BC%8816%EF%BC%89Qatten.assets/image-20200707121725186.png" alt="img"></p><h3 id="主要思路" tabindex="-1">主要思路 <a class="header-anchor" href="#主要思路" aria-label="Permalink to “主要思路”">​</a></h3><p>1、将联合动作值函数看作是独立动作值函数的函数</p><p><img src="https://liushunyu.github.io/img/in-post/2020-07-07-%E5%BC%BA%E5%8C%96%E5%AD%A6%E4%B9%A0%E8%AE%BA%E6%96%87%EF%BC%8816%EF%BC%89Qatten.assets/image-20200707122308260.png" alt="img"></p><ul><li>其中每个独立值函数必须与联合动作值函数相关</li></ul><p><img src="https://liushunyu.github.io/img/in-post/2020-07-07-%E5%BC%BA%E5%8C%96%E5%AD%A6%E4%B9%A0%E8%AE%BA%E6%96%87%EF%BC%8816%EF%BC%89Qatten.assets/image-20200707122554464.png" alt="img"></p><ul><li>在极值点处联合动作值函数对动作的导数为零</li></ul><p><img src="https://liushunyu.github.io/img/in-post/2020-07-07-%E5%BC%BA%E5%8C%96%E5%AD%A6%E4%B9%A0%E8%AE%BA%E6%96%87%EF%BC%8816%EF%BC%89Qatten.assets/image-20200707122713202.png" alt="img"></p><p>2、在极值点处独立动作值函数对动作的导数也为零，且可以对其进行泰勒局部展开</p><p><img src="https://liushunyu.github.io/img/in-post/2020-07-07-%E5%BC%BA%E5%8C%96%E5%AD%A6%E4%B9%A0%E8%AE%BA%E6%96%87%EF%BC%8816%EF%BC%89Qatten.assets/image-20200707122824468.png" alt="img"></p><p>3、将联合动作值函数在各个独立动作值函数上进行泰勒展开，并将上述独立值函数的泰勒局部展开代入，可以证明得联合动作值函数将变成独立动作值函数的一阶线性组合，具体证明看论文。</p><ul><li>此处比较巧妙的一个点是当忽略高阶项的时候，我们发现独立动作值函数的二次项部分也被忽略了，只留下了独立动作值函函数的一阶项。</li></ul><p><img src="https://liushunyu.github.io/img/in-post/2020-07-07-%E5%BC%BA%E5%8C%96%E5%AD%A6%E4%B9%A0%E8%AE%BA%E6%96%87%EF%BC%8816%EF%BC%89Qatten.assets/image-20200707122910197.png" alt="img"></p><p>4、根据上述定理设计 multiple attention heads 网络架构对理论分析结果进行逼近，直接看结构图还是很好理解的，其中不同的 attention heads 对应不同阶次的近似，而且 attention heads 的数量也决定了逼近的阶次。</p><p><img src="https://liushunyu.github.io/img/in-post/2020-07-07-%E5%BC%BA%E5%8C%96%E5%AD%A6%E4%B9%A0%E8%AE%BA%E6%96%87%EF%BC%8816%EF%BC%89Qatten.assets/image-20200707123649378.png" alt="img"></p><p>5、Qatten 算法是符合 IGM 定理的，在 QTRAN 中有提及。</p><p><img src="https://liushunyu.github.io/img/in-post/2020-07-07-%E5%BC%BA%E5%8C%96%E5%AD%A6%E4%B9%A0%E8%AE%BA%E6%96%87%EF%BC%8816%EF%BC%89Qatten.assets/image-20200707123839141.png" alt="img"></p><p>6、此外为了放松 self-attention 所施加的权重边界限制，提高 Qatten 的表现能力，论文还提出了 Weighted Head Q-value 的方法</p><p><img src="https://liushunyu.github.io/img/in-post/2020-07-07-%E5%BC%BA%E5%8C%96%E5%AD%A6%E4%B9%A0%E8%AE%BA%E6%96%87%EF%BC%8816%EF%BC%89Qatten.assets/image-20200707124341570.png" alt="img"></p><ul><li>该方法满足 Theorem 1 的结果</li></ul><p><img src="https://liushunyu.github.io/img/in-post/2020-07-07-%E5%BC%BA%E5%8C%96%E5%AD%A6%E4%B9%A0%E8%AE%BA%E6%96%87%EF%BC%8816%EF%BC%89Qatten.assets/image-20200707124448048.png" alt="img"></p><h2 id="实验" tabindex="-1">实验 <a class="header-anchor" href="#实验" aria-label="Permalink to “实验”">​</a></h2><p>1、在 StarCraft II decentralized micromanagement tasks 上进行实验</p><p>2、从实验效果上看 Qatten 只比 QMIX 好一点，而且值得注意的是 QTRAN 的效果竟然那么差，看来将约束转化为惩罚项从而求解优化问题带来的偏差还是挺大的。</p><p><img src="https://liushunyu.github.io/img/in-post/2020-07-07-%E5%BC%BA%E5%8C%96%E5%AD%A6%E4%B9%A0%E8%AE%BA%E6%96%87%EF%BC%8816%EF%BC%89Qatten.assets/image-20200707123857539.png" alt="img"></p><h2 id="其他补充" tabindex="-1">其他补充 <a class="header-anchor" href="#其他补充" aria-label="Permalink to “其他补充”">​</a></h2><p>1、该论文从理论分析到网络结构设计的思路还是很不错的，整体很流畅。</p>',33)])])}const m=a(n,[["render",E]]);export{B as __pageData,m as default};
